#include <iostream>using namespace std; int main(){    ios::sync_with_stdio(0);    cin.tie(0);     int c[1000001]={0};    int n,q;    cin>>n>>q;     for(int i=0;i<n;i++)    {        int x;        cin>>x;        c[x]++;    }     while(q--)    {        int k;        cin>>k;        if(k>0)        {            c[k]++;        }        else        {            int t=-k;            int p=0;            while(1)            {                p++;                if(c[p]>=t)                {                    c[p]--;                    break;                }                else                {                    t-=c[p];                }            }        }    }     for(int i=1;i<=1000000;i++)    {        if(c[i]>0)        {            cout<<i<<'\n';            return 0;        }    }    cout<<0<<'\n';    return 0;}